class Solution(object):
    def countPairs(self, deliciousness):
        MOD = 10**9 + 7
        result = 0
        freq = {}
        powers = [2**i for i in range(21)]
        for num in deliciousness:
            for power in powers:
                complement = power - num
                result = (result + freq.get(complement, 0)) % MOD
            freq[num] = freq.get(num, 0) + 1
        return result
